backend-service-ecr.terraform_block:
resource "aws_ecr_lifecycle_policy" "backend_service_lifecycle" {
  repository = aws_ecr_repository.backend_service.name
  policy     = <<EOF
{
  "rules": [
    {
      "rulePriority": 1,
      "description": "Expire untagged images after 1 day",
      "selection": {
        "tagStatus": "untagged",
        "countType": "sinceImagePushed",
        "countUnit": "days",
        "countNumber": 1
      },
      "action": {
        "type": "expire"
      }
    },
    {
      "rulePriority": 2,
      "description": "Keep last 30 tagged images",
      "selection": {
        "tagStatus": "tagged",
        "tagPrefixList": ["v"],
        "countType": "imageCountMoreThan",
        "countNumber": 30
      },
      "action": {
        "type": "expire"
      }
    }
  ]
}
EOF

  tags = {
    Name        = "backend-service-lifecycle"
    Environment = "production"
    FinOpsAction = "SET_LIFECYCLE"
    FinOpsReviewed = "true"
  }
}

